            $json['exchangeRate']            = $this->exchangeRate;
        }
        if (isset($this->exchangeRateTimeStamp)) {
            $json['exchangeRateTimeStamp']   = $this->exchangeRateTimeStamp;
        }
        if (isset($this->amexAdditionalAmounts)) {
            $json['amexAdditionalAmounts']   = $this->amexAdditionalAmounts;
        }
        if (isset($this->taxDetails)) {
            $json['taxDetails']              = $this->taxDetails;
        }
        if (isset($this->serviceFeeAmount)) {
            $json['serviceFeeAmount']        = $this->serviceFeeAmount;
        }
        if (isset($this->originalCurrency)) {
            $json['originalCurrency']        = $this->originalCurrency;
        }
        if (isset($this->cashbackAmount)) {
            $json['cashbackAmount']          = $this->cashbackAmount;
        }
        $json = array_merge($json, $this->additionalProperties);

        return (!$asArrayWhenEmpty && empty($json)) ? new stdClass() : $json;
    }
}
